#### Step 3: Implement the Orchestrator Service

```java
@Service
public class OrderOrchestrator {

    private final InventoryService inventoryService;
    private final PaymentService paymentService;

    @Autowired
    public OrderOrchestrator(InventoryService inventoryService, PaymentService paymentService) {
        this.inventoryService = inventoryService;
        this.paymentService = paymentService;
    }

    public void createOrder(int orderId, int quantity, double amount) throws Exception {
        try {
            // Step 1: Reserve Inventory
            inventoryService.reserveInventory(orderId, quantity);

            // Step 2: Capture Payment
            paymentService.capturePayment(orderId, amount);

            // Step 3: Confirm Order (if needed)
            confirmOrder(orderId);
        } catch (Exception e) {
            rollbackTransaction(orderId);
            throw new Exception("Failed to create order", e);
        }
    }

    private void confirmOrder(int orderId) {
        // Confirm order logic here
    }

    private void rollbackTransaction(int orderId) throws Exception {
        try {
            paymentService.refundPayment(orderId);
            inventoryService.releaseInventory(orderId);
        } catch (Exception e) {
            throw new Exception("Failed to roll back transaction", e);
        }
    }
}
```

