### Saga Pattern Setup Summary

#### 1. Overview
The Saga pattern is used to manage long-running distributed transactions across multiple services. Each service in a saga handles its part of the transaction, and if any service fails, it triggers compensating actions to undo previous steps.

#### 2. Key Components
- **Saga Manager**: Orchestrates the sequence of operations.
- **Service Operations**: Individual services that perform specific tasks.
- **Compensation Handlers**: Rollback logic for each service operation in case of failure.

#### 3. Example Setup

##### Step 1: Define Service Operations and Compensation Handlers

```java
public interface OrderService {
    void placeOrder(Order order);
}

public class OrderServiceImpl implements OrderService {

    @Override
    public void placeOrder(Order order) {
        // Place the order in the database or external service
        System.out.println("Placing order: " + order.getOrder_id());

        // Simulate a failure for demonstration purposes
        if (order.getOrder_id() == 123456) {
            throw new RuntimeException("Order placement failed");
        }
    }

    public void cancelOrder(Order order) {
        System.out.println("Canceling order: " + order.getOrder_id());
    }
}
```

##### Step 2: Define Saga Manager

```java
import org.apache.flink.api.common.functions.MapFunction;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaProducer;

public class OrderSagaManager {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.get_execution_environment();

        // Enable checkpointing with exactly-once semantics
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set the restart strategy to fixed delay with 3 retries and a delay of 10 seconds between retries
        env.setRestartStrategy(RestartStrategies.fixedDelayRestart(
            3,
            Time.seconds(10)
        ));

        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");

        FlinkKafkaConsumer<Order> kafkaConsumer = new FlinkKafkaConsumer<>(
            "orders_topic",
            new KafkaAvroDeserializer(Order.class),
            kafkaProps
        );

        OrderService orderService = new OrderServiceImpl();

        env.addSource(kafkaConsumer)
           .map(new MapFunction<Order, Void>() {
               @Override
               public Void map(Order value) throws Exception {
                   try {
                       // Step 1: Place the order
                       System.out.println("Placing order...");
                       orderService.placeOrder(value);

                       // If successful, commit the transaction (no need for further steps)
                       return null;
                   } catch (Exception e) {
                       // Step 2: Cancel the order if placement fails
                       System.out.println("Order placement failed. Cancelling order...");
                       orderService.cancelOrder(value);
                       throw new RuntimeException("Failed to place order", e);
                   }
               }
           })
           .addSink(new FlinkKafkaProducer<>(
               "order_status_topic",
               new KafkaAvroSerializer<>(Void.class),
               kafkaProps,
               FlinkKafkaProducer.Semantic.EXACTLY_ONCE
           ));

        env.execute("Order Saga Manager with Restart Strategy and Exactly-Once Semantics");
    }
}
```

