To comply with the new rule that requires each compensation step to write an audit entry to `saga_audit` before running the actual compensation logic, you need to modify your Saga implementation. Here's how you can integrate this requirement into your existing setup:

### Step-by-Step Implementation

1. **Define Audit Table Schema**

   First, define a schema for the `saga_audit` table that will store audit entries.

   ```sql
   CREATE TABLE saga_audit (
       id BIGINT AUTO_INCREMENT PRIMARY KEY,
       saga_id VARCHAR(255) NOT NULL,
       step VARCHAR(255) NOT NULL,
       status VARCHAR(255) NOT NULL,  -- e.g., "PENDING", "SUCCESS", "FAILED"
       timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP
   );
   ```

2. **Modify Compensation Logic to Write Audit Entries**

   Before running the actual compensation logic, write an audit entry to `saga_audit` with the necessary details.

3. **Example Implementation in Java/Spring Boot**

   Here’s how you can implement this in a Spring Boot application:

   ```java
   import org.springframework.beans.factory.annotation.Autowired;
   import org.springframework.stereotype.Service;
   import org.springframework.transaction.annotation.Transactional;

   @Service
   public class OrderOrchestrator {

       private final SagaAuditRepository sagaAuditRepository;
       private final InventoryService inventoryService;
       private final PaymentService paymentService;

       @Autowired
       public OrderOrchestrator(SagaAuditRepository sagaAuditRepository, InventoryService inventoryService, PaymentService paymentService) {
           this.sagaAuditRepository = sagaAuditRepository;
           this.inventoryService = inventoryService;
           this.paymentService = paymentService;
       }

       public void createOrder(int orderId, int quantity, double amount) throws Exception {
           try {
               // Step 1: Reserve Inventory
               reserveInventory(orderId, quantity);

               // Step 2: Capture Payment
               capturePayment(orderId, amount);

               // Step 3: Confirm Order (if needed)
               confirmOrder(orderId);
           } catch (Exception e) {
               rollbackTransaction(orderId);
               throw new Exception("Failed to create order", e);
           }
       }

       private void reserveInventory(int orderId, int quantity) throws Exception {
           sagaAuditRepository.save(new SagaAuditEntry(orderId, "RESERVE_INVENTORY", "PENDING"));
           inventoryService.reserveInventory(orderId, quantity);
           sagaAuditRepository.updateStatus(orderId, "RESERVE_INVENTORY", "SUCCESS");
       }

       private void capturePayment(int orderId, double amount) throws Exception {
           sagaAuditRepository.save(new SagaAuditEntry(orderId, "CAPTURE_PAYMENT", "PENDING"));
           paymentService.capturePayment(orderId, amount);
           sagaAuditRepository.updateStatus(orderId, "CAPTURE_PAYMENT", "SUCCESS");
       }

       private void confirmOrder(int orderId) {
           // Confirm order logic here
           sagaAuditRepository.save(new SagaAuditEntry(orderId, "CONFIRM_ORDER", "PENDING"));
           // Assuming confirmation is successful for simplicity
           sagaAuditRepository.updateStatus(orderId, "CONFIRM_ORDER", "SUCCESS");
       }

       private void rollbackTransaction(int orderId) throws Exception {
           try {
               sagaAuditRepository.save(new SagaAuditEntry(orderId, "REFUND_PAYMENT", "PENDING"));
               paymentService.refundPayment(orderId);
               sagaAuditRepository.updateStatus(orderId, "REFUND_PAYMENT", "SUCCESS");

               sagaAuditRepository.save(new SagaAuditEntry(orderId, "RELEASE_INVENTORY", "PENDING"));
               inventoryService.releaseInventory(orderId);
               sagaAuditRepository.updateStatus(orderId, "RELEASE_INVENTORY", "SUCCESS");
           } catch (Exception e) {
               throw new Exception("Failed to roll back transaction", e);
           }
       }

       @Transactional(rollbackFor = Exception.class)
       public void reserveInventory(int orderId, int quantity) throws Exception {
           // Reserve inventory logic here
           if (!inventoryService.inventoryIsAvailable(quantity)) {
               throw new InsufficientStockException("Insufficient stock for order");
           }
           // Mark inventory as reserved
       }

       @Transactional(rollbackFor = Exception.class)
       public void releaseInventory(int orderId) {
           // Release inventory logic here
       }

       @Transactional(rollbackFor = Exception.class)
       public void capturePayment(int orderId, double amount) throws PaymentException {
           // Capture payment logic here
           if (!paymentService.paymentIsSuccessful(amount)) {
               throw new PaymentException("Failed to capture payment");
           }
           // Mark payment as captured
       }

       @Transactional(rollbackFor = Exception.class)
       public void refundPayment(int orderId) {
           // Refund payment logic here
       }
   }
