                // Handle transient errors and retry
                if (!shouldRetry(e)) {
                    throw e;
                }
                int retries = 0;
                while (retries < 3) {
                    try {
                        Thread.sleep(100 * Math.pow(2, retries));
                        return "Processed: " + value;
                    } catch (Exception ex) {
                        retries++;
                    }
                }
                // Send to failure topic after all retries
                throw new RuntimeException("Failed after retries", e);
