    public static void registerSchemaWithCompatibility(SchemaRegistryClient schemaRegistryClient, String subject, Schema avroSchema) throws Exception {
        CompatibilityModeRequest compatibilityMode = new CompatibilityModeRequest(CompatibilityMode.BACKWARD_TRANSITIVE);
