        kafkaProps.setProperty("enable.auto.commit", "false"); // Disable auto-commit to manage manually
        kafkaProps.setProperty("isolation.level", "read_committed"); // Ensure exactly-once semantics

        // Define Kafka consumer for Avro messages
        FlinkKafkaConsumer<OrderCreatedEvent> kafkaConsumer = new FlinkKafkaConsumer<>(
            "order-created",
            new KafkaAvroDeserializationSchema<>(OrderCreatedEvent.class),
