    private Long id;

    private String eventType;

    private String payload; // JSONB column

    private String status;

    public OrderOutbox() {}

    public OrderOutbox(String eventType, String payload) {
        this.eventType = eventType;
        this.payload = payload;
    }

    // Getters and setters
}
```

#### 3. Create Kafka Transactional Producer Bean
Configure a transactional Kafka producer in your Spring Boot application.

