import org.apache.flink.streaming.api.TimeCharacteristic;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;

public class OrderProcessingJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set up the environment to use event time
        env.setStreamTimeCharacteristic(TimeCharacteristic.EventTime);

        // Configure checkpointing for exactly-once semantics
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "flink-consumer-group");

        FlinkKafkaConsumer<OrderCreatedEvent> kafkaConsumer = new FlinkKafkaConsumer<>(
            "order-created",
            new KafkaAvroDeserializationSchema<>(OrderCreatedEvent.class),
            kafkaProps
        );

        // Apply the watermark strategy
        DataStream<OrderCreatedEvent> orderEvents = env.addSource(kafkaConsumer)
            .assignTimestampsAndWatermarks(new EventTimeAssigner());

        processOrders(orderEvents);

        env.execute("Order Processing Job");
    }

    private void processOrders(DataStream<OrderCreatedEvent> orderEvents) {
        // Example processing logic: Count orders per customer in a sliding window
        DataStream<Tuple2<String, Integer>> orderCountPerCustomer = orderEvents
            .map(event -> new Tuple2<>(event.getCustomerId(), 1))
            .keyBy(0)
            .timeWindow(Time.minutes(5), Time.seconds(30)) // Sliding window of 5 minutes with a slide of 30 seconds
            .sum(1);

        orderCountPerCustomer.print();
    }
}
```

