    private EventStore eventStore;

    public void processOrder(CreateOrderCommand command) {
        try {
            // Emit events for each step
            OrderCreatedEvent orderCreated = new OrderCreatedEvent();
            orderCreated.setEventType("ORDER_CREATED");
            orderCreated.setTimestamp(System.currentTimeMillis());
            orderCreated.setOrderId(command.getOrderId());
            orderCreated.setCustomerId(command.getCustomerId());
            orderCreated.setItems(command.getItems());
            orderCreated.setTotalAmount(command.getTotalAmount());

            eventStore.save(orderCreated);

            // Confirm payment
            PaymentConfirmedEvent paymentConfirmed = new PaymentConfirmedEvent();
            paymentConfirmed.setEventType("PAYMENT_CONFIRMED");
            paymentConfirmed.setTimestamp(System.currentTimeMillis());
            paymentConfirmed.setOrderId(command.getOrderId());

            eventStore.save(paymentConfirmed);

            // Reserve stock
            StockReservedEvent stockReserved = new StockReservedEvent();
            stockReserved.setEventType("STOCK_RESERVED");
            stockReserved.setTimestamp(System.currentTimeMillis());
            stockReserved.setOrderId(command.getOrderId());
            stockReserved.setItems(command.getItems());

            eventStore.save(stockReserved);

        } catch (Exception e) {
            // Rollback the transaction and emit compensation events
            try {
                StockReleasedEvent stockReleased = new StockReleasedEvent();
                stockReleased.setEventType("STOCK_RELEASED");
                stockReleased.setTimestamp(System.currentTimeMillis());
                stockReleased.setOrderId(command.getOrderId());

