            jdbcTemplate.execute("BEGIN");

            // Create the order
            jdbcTemplate.update("INSERT INTO orders (order_id, customer_id, items, total_amount) VALUES (?, ?, ?, ?)",
                                command.getOrderId(), command.getCustomerId(), command.getItems(), command.getTotalAmount());

            // Confirm payment
            jdbcTemplate.update("CALL confirm_payment(?)", command.getOrderId());

            // Reserve stock
            jdbcTemplate.update("CALL reserve_stock(?, ?)", command.getOrderId(), command.getItems());

            // Commit the transaction if all steps are successful
            jdbcTemplate.execute("COMMIT");

        } catch (Exception e) {
            // Rollback the transaction and emit compensation events
            try {
                jdbcTemplate.execute("ROLLBACK");

                sagaAuditService.writeAuditEntry(sagaId, "release_stock", "STARTED");
                inventoryManagementSystem.releaseStock(command.getOrderId());

                sagaAuditService.writeAuditEntry(sagaId, "cancel_payment", "STARTED");
                paymentGateway.cancelPayment(command.getOrderId());

                sagaAuditService.writeAuditEntry(sagaId, "cancel_order", "STARTED");
                orderService.cancelOrder(command.getOrderId());

                // Emit compensation events for each step
                OrderCompensationEvent compensationEvent = new OrderCompensationEvent();
                compensationEvent.setEventType("ORDER_CANCELLED");
                compensationEvent.setTimestamp(System.currentTimeMillis());
                compensationEvent.setOrderId(command.getOrderId());
                compensationEvent.setActionType("cancel_order");

                kafkaOrderCompensationTemplate.send("order-cancelled", compensationEvent);

            } catch (Exception rollbackException) {
                System.err.println("Failed to roll back transaction: " + rollbackException.getMessage());
            }
        }
    }
}
