import org.apache.kafka.clients.producer.ProducerConfig;
import org.apache.kafka.common.serialization.StringSerializer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.kafka.core.DefaultKafkaProducerFactory;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.transaction.KafkaTransactionManager;

@Configuration
public class KafkaConfiguration {

    @Bean
    public DefaultKafkaProducerFactory<String, String> producerFactory() {
        Map<String, Object> configProps = new HashMap<>();
        configProps.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        configProps.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        configProps.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        configProps.put(ProducerConfig.TRANSACTIONAL_ID_CONFIG, "transactional-producer-id");
        return new DefaultKafkaProducerFactory<>(configProps);
    }

    @Bean
    public KafkaTemplate<String, String> kafkaTemplate() {
        return new KafkaTemplate<>(producerFactory());
    }
}
```

#### 3. Configure Transaction Manager

Set up a `KafkaTransactionManager` to manage transactions.

```java
import org.apache.kafka.clients.producer.Producer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class KafkaConfiguration {

    @Bean
    public KafkaTransactionManager<String, String> transactionManager(ProducerFactory<String, String> producerFactory) {
        return new KafkaTransactionManager<>(producerFactory);
    }
}
```

#### 4. Use Transactional Template in Service

Inject the `KafkaTemplate` and use it within a transaction.

```java
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.PlatformTransactionManager;
import org.springframework.transaction.TransactionStatus;
import org.springframework.transaction.support.DefaultTransactionDefinition;

@Service
public class OrderPlacementService {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final PlatformTransactionManager transactionManager;

    @Autowired
    public OrderPlacementService(KafkaTemplate<String, String> kafkaTemplate, PlatformTransactionManager transactionManager) {
        this.kafkaTemplate = kafkaTemplate;
        this.transactionManager = transactionManager;
    }

    public void placeOrder(OrderRequest request) {
        TransactionStatus status = transactionManager.getTransaction(new DefaultTransactionDefinition());

        try {
            // Business logic for placing an order

            String orderId = generateOrderId();
            List<String> items = request.getItems();

            OrderPlacedEvent event = new OrderPlacedEvent(orderId, items);
            kafkaTemplate.send("order_events", "key", event.toJson());

            transactionManager.commit(status);  // Commit the transaction
        } catch (Exception e) {
            transactionManager.rollback(status);  // Rollback the transaction on failure
            throw e;
        }
    }

    private String generateOrderId() {
        return UUID.randomUUID().toString();
    }
}
```

