    username: postgres
    password: postgres
```

#### 3. Define Service Logic

Implement the service logic to consume messages, process them using PostgreSQL transactions, and commit or rollback based on success.

```java
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.transaction.KafkaTransactionManager;
import org.springframework.stereotype.Service;
import org.springframework.transaction.PlatformTransactionManager;

@Service
public class OrderFulfillmentService {

    @Autowired
    private JdbcTemplate jdbcTemplate;

    @Autowired
    private PlatformTransactionManager transactionManager;

    @KafkaListener(topics = "order_events", groupId = "order-processing-group")
    public void handleOrderPlacedEvent(ConsumerRecord<String, String> record) {
        try {
            // Deserialize the event from Kafka (assuming JSON format)
            OrderPlacedEvent event = new ObjectMapper().readValue(record.value(), OrderPlacedEvent.class);

            // Start a transaction
            TransactionStatus status = transactionManager.getTransaction(new DefaultTransactionDefinition());

            try {
