import org.apache.flink.api.common.serialization.SimpleStringSchema;
import org.apache.flink.streaming.api.CheckpointingMode;
import org.apache.flink.streaming.api.datastream.DataStream;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaProducer;

public class OrderProcessingJob {

    public static void main(String[] args) throws Exception {
        // Create the execution environment
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpoint configuration (optional but recommended for resiliency)
        env.enableCheckpointing(5000);  // Checkpoint every 5 seconds
        env.getCheckpointConfig().setCheckpointingMode(CheckpointingMode.EXACTLY_ONCE);

        // Configure the restart strategy as per ops runbook
        env.getConfig().setRestartStrategy(RestartStrategies.fixedDelayRestart(
            3,  // Number of restart attempts
            Time.seconds(10)  // Delay between restarts in seconds
        ));

        // Define source and sink topics
        String inputTopic = "order_events";
        String outputTopic = "order_fulfillment";

        // Kafka consumer configuration
        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "flink-consumer-group");

        DataStream<String> orderEvents = env.addSource(new FlinkKafkaConsumer<>(inputTopic, new SimpleStringSchema(), kafkaProps));

        // Example processing logic (e.g., filter orders based on some condition)
        DataStream<OrderPlacedEvent> filteredOrders = orderEvents
            .map(order -> {
                ObjectMapper objectMapper = new ObjectMapper();
                return objectMapper.readValue(order, OrderPlacedEvent.class);
            })
            .filter(event -> event.getItems().size() > 0); // Example filtering logic

        // Kafka producer configuration
        FlinkKafkaProducer<String> kafkaSink = new FlinkKafkaProducer<>(
            outputTopic,
            order -> {
                ObjectMapper objectMapper = new ObjectMapper();
                return objectMapper.writeValueAsString(order);
            },
            kafkaProps);

        filteredOrders.addSink(kafkaSink);

        // Execute the job
        env.execute("Order Processing Job");
    }
}
```

### Explanation

1. **Execution Environment**: Create an execution environment for your Flink job.
2. **Checkpointing Configuration**:
   - Enable checkpointing every 5 seconds to ensure fault tolerance.
   - Set the checkpoint mode to `EXACTLY_ONCE` for strong consistency guarantees.
3. **Restart Strategy**:
   - Configure a fixed delay restart strategy with up to 3 attempts and a 10-second delay between retries.
4. **Kafka Consumer Configuration**:
   - Define properties for connecting to Kafka, including the bootstrap servers and consumer group ID.
5. **Data Stream Processing**:
