@Service
public class OrderPlacementService {

    @Autowired
    private JdbcTemplate jdbcTemplate;

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void placeOrder(OrderRequest request) {
        // Generate order ID and event payload
        String orderId = generateOrderId();
        List<OrderItem> items = request.getItems();

        OrderPlacedEvent event = new OrderPlacedEvent(orderId, items);

        // Write to outbox table
        jdbcTemplate.update("INSERT INTO order_outbox (id, event_type, payload) VALUES (?, ?, ?)",
                UUID.randomUUID(), "ORDER_PLACED", new ObjectMapper().writeValueAsString(event));

        // Publish to Kafka using transactional producer
        kafkaTemplate.executeInTransaction(tx -> {
            tx.send("order_events", orderId, event.toJson());
            return null;
        });
    }

    private String generateOrderId() {
        return UUID.randomUUID().toString();
    }
}
