        // Perform aggregation or transformation on the data stream
        DataStream<AggregatedOrderData> aggregatedOrders = filteredOrders
            .keyBy(OrderPlacedEvent::getOrderId)
            .reduce((event1, event2) -> {
                // Aggregation logic here (e.g., summing quantities, calculating totals)
                return new OrderPlacedEvent(event1.getOrderId(), event1.getItems());
