            inventoryService.adjustInventory(record.value());
            consumer.commitSync(Collections.singletonMap(new TopicPartition(record.topic(), record.partition()), new OffsetAndMetadata(record.offset() + 1)));
        } catch (Exception e) {
            logger.error("Failed to process order created event: " + record.toString(), e);
            // Retry logic or dead letter queue handling
            if (!retryTemplate.execute(context -> {
                try {
                    inventoryService.adjustInventory(record.value());
                    consumer.commitSync(Collections.singletonMap(new TopicPartition(record.topic(), record.partition()), new OffsetAndMetadata(record.offset() + 1)));
                    return null;
                } catch (Exception ex) {
                    logger.error("Failed to process order created event after retry: " + record.toString(), ex);
                    sendToDLQ(record);
                    throw ex; // Rethrow exception to trigger next retry
                }
            })) {
                logger.warn("Max retries reached for message, moving to DLQ");
                sendToDLQ(record);
            }
        }
    }

    private void sendToDLQ(ConsumerRecord<String, GenericRecord> record) {
        kafkaTemplate.send("order-created-dlq", record.key(), record.value());
    }
