    @Autowired
    private NotificationService notificationService;

    public void processOrder(Order order) {
        try {
            // Step 1: Create order in the Order Service
            String orderId = orderService.createOrder(order);

            // Step 2: Adjust inventory levels in the Inventory Service
            inventoryService.adjustInventory(orderId, order.getItems());

            // Step 3: Process payment in the Payment Service
            paymentService.processPayment(orderId, order.getTotalAmount());

            // Step 4: Send confirmation email in the Notification Service
            notificationService.sendConfirmationEmail(orderId);

        } catch (Exception e) {
            logger.error("Error processing order", e);

            // Emit compensation events and rollback operations if any step fails
            try {
                paymentService.refundPayment(order.getId());
                kafkaTemplate.send("order-cancelled", new OrderCancelledEvent(order.getId(), System.currentTimeMillis()));
            } catch (Exception ex) {
                logger.error("Failed to refund payment", ex);
            }

            try {
                inventoryService.revertInventoryAdjustment(order.getId());
                kafkaTemplate.send("inventory-reverted", new InventoryRevertedEvent(orderId, System.currentTimeMillis()));
            } catch (Exception ex) {
                logger.error("Failed to revert inventory adjustment", ex);
            }

            try {
                orderService.cancelOrder(order.getId());
                kafkaTemplate.send("order-cancelled", new OrderCancelledEvent(order.getId(), System.currentTimeMillis()));
            } catch (Exception ex) {
                logger.error("Failed to cancel order", ex);
            }
        }
    }
}
```

#### 6. **Dead-Letter Queue (DLQ)**

Handle poison pills by moving failed messages to a DLQ for further analysis or reprocessing.

**Example DLQ Handling:**
```java
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Component;

@Component
public class InventoryConsumer {

    @Autowired
    private KafkaTemplate<String, OrderEvent> kafkaTemplate;

    @KafkaListener(topics = "order-created", groupId = "inventory-group")
    public void listenOrderCreated(ConsumerRecord<String, OrderEvent> record) {
        try {
            // Process the order creation event and adjust inventory accordingly
            inventoryService.adjustInventory(record.value());

            consumer.commitSync(Collections.singletonMap(new TopicPartition(record.topic(), record.partition()), new OffsetAndMetadata(record.offset() + 1)));
        } catch (Exception e) {
            logger.error("Failed to process order created event: " + record.toString(), e);
            sendToDLQ(record); // Send failed message to DLQ
        }
    }

    private void sendToDLQ(ConsumerRecord<String, OrderEvent> record) {
        kafkaTemplate.send("order-created-dlq", record.key(), record.value());
    }
}
```

